func (this *OnetradingCore) ParseMarket(market any) any {
	//
	//   {
	//      "base":{
	//         "code":"BTC",
	//         "precision":"5"
	//      },
	//      "quote":{
	//         "code":"USDC",
	//         "precision":"2"
	//      },
	//      "amount_precision":"5",
	//      "market_precision":"2",
	//      "min_size":"10.0",
	//      "min_price":"1000",
	//      "max_price":"10000000",
	//      "id":"BTC_USDC",
	//      "type":"SPOT",
	//      "state":"ACTIVE"
	//   }
	//
	//
	//  {
	//      "base": {
	//          "code": "BTC",
	//          "precision": 5
	//      },
	//      "quote": {
	//          "code": "EUR",
	//          "precision": 2
	//      },
	//      "amount_precision": 5,
	//      "market_precision": 2,
	//      "min_size": "10.0",
	//      "min_price": "1000",
	//      "max_price": "10000000",
	//      "id": "BTC_EUR_P",
	//      "type": "PERP",
	//      "state": "ACTIVE"
	//  }
	//
	var baseAsset any = this.SafeDict(market, "base", map[string]any{})
	var quoteAsset any = this.SafeDict(market, "quote", map[string]any{})
	var baseId any = this.SafeString(baseAsset, "code")
	var quoteId any = this.SafeString(quoteAsset, "code")
	var id any = this.SafeString(market, "id")
	var base any = this.SafeCurrencyCode(baseId)
	var quote any = this.SafeCurrencyCode(quoteId)
	var state any = this.SafeString(market, "state")
	var typeVar any = this.SafeString(market, "type")
	var isPerp any = IsEqual(typeVar, "PERP")
	var symbol any = Add(Add(base, "/"), quote)
	if IsTrue(isPerp) {
		symbol = Add(Add(symbol, ":"), quote)
	}
	return map[string]any{
		"id":             id,
		"symbol":         symbol,
		"base":           base,
		"quote":          quote,
		"settle":         Ternary(IsTrue(isPerp), quote, nil),
		"baseId":         baseId,
		"quoteId":        quoteId,
		"settleId":       Ternary(IsTrue(isPerp), quoteId, nil),
		"type":           Ternary(IsTrue(isPerp), "swap", "spot"),
		"spot":           !IsTrue(isPerp),
		"margin":         false,
		"swap":           isPerp,
		"future":         false,
		"option":         false,
		"active":         (IsEqual(state, "ACTIVE")),
		"contract":       isPerp,
		"linear":         Ternary(IsTrue(isPerp), true, nil),
		"inverse":        Ternary(IsTrue(isPerp), false, nil),
		"contractSize":   Ternary(IsTrue(isPerp), this.ParseNumber("1"), nil),
		"expiry":         nil,
		"expiryDatetime": nil,
		"strike":         nil,
		"optionType":     nil,
		"precision": map[string]any{
			"amount": this.ParseNumber(this.ParsePrecision(this.SafeString(market, "amount_precision"))),
			"price":  this.ParseNumber(this.ParsePrecision(this.SafeString(market, "market_precision"))),
		},
		"limits": map[string]any{
			"leverage": map[string]any{
				"min": nil,
				"max": nil,
			},
			"amount": map[string]any{
				"min": nil,
				"max": nil,
			},
			"price": map[string]any{
				"min": nil,
				"max": nil,
			},
			"cost": map[string]any{
				"min": this.SafeNumber(market, "min_size"),
				"max": nil,
			},
		},
		"created": nil,
		"info":    market,
	}
}

